from __future__ import annotations

import os
import sys
import json
import tempfile
import threading
import time
from typing import Any

from pydbus import SessionBus
from gi.repository import GLib


KWIN_SERVICE   = "org.kde.KWin"
SCRIPTING_PATH = "/Scripting"
VDM_PATH       = "/VirtualDesktopManager"
KWIN_PATH      = "/KWin"


class GLibLoop:
    """
    Manages a GLib main loop running in a daemon thread.
    Required for pydbus to dispatch incoming D-Bus method calls.
    Call start() before publishing any D-Bus services,
    stop() when done.
    """

    def __init__(self) -> None:
        self._loop:   GLib.MainLoop | None = None
        self._thread: threading.Thread | None = None

    def start(self) -> None:
        if self._loop is not None:
            return   # already running
        self._loop   = GLib.MainLoop()
        self._thread = threading.Thread(target=self._loop.run, daemon=True)
        self._thread.start()

    def stop(self) -> None:
        if self._loop is not None:
            try:
                self._loop.quit()
            except Exception:
                pass
            self._loop   = None
            self._thread = None

    def __enter__(self) -> "GLibLoop":
        self.start()
        return self

    def __exit__(self, *_) -> None:
        self.stop()


class KWinBus:
    """
    Connects to KWin's D-Bus services on the session bus.
    Provides access to the scripting interface and VirtualDesktopManager.
    """

    def __init__(self, bus: SessionBus) -> None:
        self._bus = bus
        self._scripting = None
        self._vdm       = None
        self._kwin      = None

    @property
    def scripting(self):
        """org.kde.kwin.Scripting at /Scripting"""
        if self._scripting is None:
            self._scripting = self._bus.get(KWIN_SERVICE, SCRIPTING_PATH)
        return self._scripting

    @property
    def vdm(self):
        """org.kde.KWin.VirtualDesktopManager at /VirtualDesktopManager"""
        if self._vdm is None:
            self._vdm = self._bus.get(KWIN_SERVICE, VDM_PATH)
        return self._vdm

    @property
    def kwin(self):
        """org.kde.KWin at /KWin"""
        if self._kwin is None:
            self._kwin = self._bus.get(KWIN_SERVICE, KWIN_PATH)
        return self._kwin

    def get_window_info(self, uuid: str) -> dict[str, Any] | None:
        """
        Call KWin's getWindowInfo() D-Bus method directly for a UUID.
        Returns a plain Python dict or None on failure.
        Note: this only works for UUIDs you already have — there is no
        D-Bus method to enumerate all windows in this KWin version.
        """
        wrapped = uuid if uuid.startswith("{") else f"{{{uuid}}}"
        try:
            raw = self.kwin.getWindowInfo(wrapped)
            if not raw:
                return None
            return {str(k): self._unwrap(v) for k, v in raw.items()}
        except Exception:
            return None

    @staticmethod
    def _unwrap(value: Any) -> Any:
        if hasattr(value, "unpack"):
            return value.unpack()
        if isinstance(value, dict):
            return {str(k): KWinBus._unwrap(v) for k, v in value.items()}
        if isinstance(value, (list, tuple)):
            return [KWinBus._unwrap(i) for i in value]
        return value


class ScriptRunner:
    """
    Loads a KWin JavaScript snippet as a temporary script, runs it,
    waits for a callDBus() callback, then unloads the script.

    The JS body has access to:
      - All workspace.* APIs (windowList, desktops, screens, activeWindow, …)
      - callDBus() for calling back to a Python D-Bus service
      - send(data) helper injected by this runner

    Usage:
        runner = ScriptRunner(kwin_bus, receiver_service, receiver_path,
                              receiver_iface)
        result = runner.run("my_test", "send({ hello: 'world' });")
    """

    def __init__(
        self,
        kwin_bus:        KWinBus,
        receiver_service: str,
        receiver_path:    str,
        receiver_iface:   str,
    ) -> None:
        self._kwin            = kwin_bus
        self._receiver_service = receiver_service
        self._receiver_path    = receiver_path
        self._receiver_iface   = receiver_iface
        self._events: dict[str, threading.Event]  = {}
        self._results: dict[str, Any]             = {}
        self._lock = threading.Lock()

    def register_result(self, name: str, data: Any) -> None:
        """Called by the D-Bus receiver when a script sends a result."""
        with self._lock:
            self._results[name] = data
            ev = self._events.get(name)
        if ev:
            ev.set()

    def run(
        self,
        name:    str,
        js_body: str,
        timeout: float = 8.0,
    ) -> dict[str, Any]:
        """
        Wrap *js_body* with boilerplate, load it as a KWin script,
        wait for a send() callback, unload, and return the result dict.

        Returns {"timeout": True} if no callback arrives within *timeout*,
        or {"loadError": ...} / {"fatalError": ...} on failure.

        Note on unloading: loadScript(path) returns a numeric ID.
        unloadScript() on this KWin version accepts only the numeric ID
        as a string — the two-argument form of loadScript is not available.
        The /Scripting/ScriptN D-Bus objects accumulate for the KWin session
        lifetime; this is a KWin internal bookkeeping limitation, not a leak
        in our code.
        """
        js = self._wrap(name, js_body)

        fd, path = tempfile.mkstemp(suffix=".js", prefix=f"kwin_lib_{name}_")
        os.close(fd)

        ev = threading.Event()
        with self._lock:
            self._events[name] = ev

        script_id = None
        try:
            with open(path, "w") as f:
                f.write(js)
            script_id = self._kwin.scripting.loadScript(path)
            self._kwin.scripting.start()
        except Exception as exc:
            try: os.unlink(path)
            except OSError: pass
            return {"loadError": str(exc)}

        t_start = time.monotonic()
        ev.wait(timeout=timeout)
        elapsed_ms = int((time.monotonic() - t_start) * 1000)

        # Cleanup regardless of outcome
        try:
            if script_id is not None:
                self._kwin.scripting.unloadScript(str(script_id))
        except Exception:
            pass
        try:
            os.unlink(path)
        except OSError:
            pass

        with self._lock:
            result = self._results.get(name)

        if result is None:
            return {"timeout": True, "elapsed_ms": elapsed_ms}
        if isinstance(result, dict):
            result["elapsed_ms"] = elapsed_ms
        return result

    def _wrap(self, name: str, js_body: str) -> str:
        """Wrap a JS body with the send() helper and error catcher."""
        svc   = self._receiver_service
        path  = self._receiver_path
        iface = self._receiver_iface
        return f"""
// kwin_lib script: {name}
var __svc="{svc}",__path="{path}",__iface="{iface}",__name="{name}";
function send(d){{
    callDBus(__svc,__path,__iface,"receiveResult",__name,JSON.stringify(d));
}}
try{{
    {js_body}
}}catch(e){{
    send({{fatalError:String(e),scriptName:"{name}"}});
}}
"""


class CallbackReceiver:
    """
    Base class for Python-side D-Bus services that KWin scripts call back into.

    Subclasses implement the actual interface methods.
    This class provides the receiveResult() relay used by ScriptRunner.

    Usage:
        class MyReceiver(CallbackReceiver):
            INTERFACE_NAME = "org.probe.MyService"
            INTERFACE_XML  = "<node>...</node>"

            def myMethod(self, arg): ...

        bus = SessionBus()
        receiver = MyReceiver(runner)
        reg = bus.publish("org.probe.MyService", ("/Path", receiver))
    """

    def __init__(self, runner: ScriptRunner | None = None) -> None:
        self._runner = runner

    def receiveResult(self, test_name: str, json_data: str) -> None:
        """Relay from KWin script back to ScriptRunner."""
        try:
            data = json.loads(json_data)
        except Exception as exc:
            data = {"parseError": str(exc), "raw": json_data[:300]}
        if self._runner is not None:
            self._runner.register_result(test_name, data)
